-- Enrichment marathon batch: Manage My Damn Life, ManageEngine ServiceDesk Plus, Manatal, Mangools, Manticore Search, Manyfold, MarginEdge, MariaDB

-- ── Manage My Damn Life ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Manage My Damn Life (MMDL) is a free, open-source, self-hosted web app that gives CalDAV task and calendar data a modern, unified interface.$q$, short_description),
  pricing_model = COALESCE($q$Open Source (self-hosted)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Manage My Damn Life Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Manage My Damn Life (MMDL) is a free, self-hosted CalDAV task and calendar manager. See features, setup and alternatives in this 2026 review.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Manage My Damn Life (MMDL) is a free, open-source, self-hosted web application that acts as a personal front end for CalDAV-based task and calendar management. It is built and maintained by the developer/team behind Intri (GitHub handle intri-in) and distributed as a Next.js application in the repository intri-in/manage-my-damn-life-nextjs. Rather than storing data on a proprietary backend, MMDL connects to any CalDAV-compatible server, such as Nextcloud, Baikal, or Radicale, and layers a modern interface for tasks, sub-tasks, and calendar events on top of it. This places MMDL in the self-hosted, home-lab software category rather than the traditional SaaS category, and it is commonly deployed via Docker or through community Proxmox VE install scripts alongside other self-hosted tools. Core functionality centers on task management: users can create tasks with due dates, status, descriptions, recurrence rules, and nested sub-tasks, and view them as a flat list, a Gantt-style timeline, or a calendar, with customizable filters. MMDL supports multiple CalDAV accounts and multiple user accounts from a single instance, so a household or small team can share one deployment while keeping separate task lists and calendars. It includes OAuth-based authentication and can run on SQLite for lightweight hosting. The maintainer describes the project as being in beta, with GitHub release history showing active development into 2025, including fixes for webcal event handling and SQLite support. Because MMDL has no company behind it in the traditional sense, there is no funding history, employee count, or corporate headquarters to report; it operates as a community open-source project rather than a venture-backed business. Pricing is effectively free: the software carries no license fee, and total cost of ownership is limited to whatever hosting the user already runs, such as a small VPS, home server, or Proxmox container, which is the core appeal of the self-hosted model. A public demo instance is available for evaluation before self-hosting. MMDL's target audience is privacy-conscious, technically comfortable individuals and small households who already run other self-hosted services, such as media servers or file sync tools, and want a task and calendar app that keeps their data under their own control rather than in a commercial cloud. It competes less with mainstream SaaS productivity apps like Todoist, TickTick, or Any.do on feature breadth or mobile polish, and more with other self-hosted CalDAV front ends and open-source task managers, where the differentiator is direct CalDAV interoperability, self-hosting control, and no subscription cost. As a young, community-maintained beta project, prospective users should expect a smaller feature set and less long-term support certainty than an established commercial product, and should keep independent backups of their CalDAV data.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5876a809-20b6-4a29-bd49-189eea244f05';

