-- ── MariaDB ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$MariaDB is a free, open-source relational database management system forked from MySQL, offering community and commercial enterprise and cloud editions.$q$, short_description),
  pricing_model = COALESCE($q$Open Source (free Community Server), with paid Enterprise and cloud offerings$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Server)$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Espoo, Finland (MariaDB plc)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$MariaDB Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$MariaDB is the open-source MySQL fork used widely across Linux distros. See its history, features, pricing, and how it compares to MySQL and Postgres.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$MariaDB is an open-source relational database management system forked from MySQL in 2009, shortly after Oracle Corporation's acquisition of Sun Microsystems raised concerns among the original MySQL developers about the database's future licensing and governance under new corporate ownership. The fork was led by Michael 'Monty' Widenius, one of MySQL's original creators, along with fellow MySQL co-founders David Axmark and Allan Larsson. MariaDB was officially founded on October 29, 2009, a date chosen to mark the birthday of Monty's daughter Maria, after whom the project is named; its first release, MariaDB 5.1.38, shipped that same day. To ensure the project's long-term independence from any single commercial owner, its founders established a dual structure: the nonprofit MariaDB Foundation was formed in December 2012 to govern and safeguard the open-source codebase independently of commercial interests, while a separate commercial entity, formed in April 2013 through the merger of Monty Program Ab and SkySQL Corporation Ab (and later operating as MariaDB Corporation, then MariaDB plc), develops and sells enterprise products, support, and cloud services around the open-source core. This foundation-plus-corporation model deliberately mirrors the structure that helped sustain Red Hat and the Linux kernel. MariaDB is released under the GNU General Public License and is designed as a drop-in replacement for MySQL, meaning applications, drivers, and most SQL syntax written for MySQL generally work against MariaDB with little or no modification, though the two projects have gradually diverged in some newer features. It uses a pluggable storage engine architecture, letting users choose different storage engines for different workloads, and the broader MariaDB product family includes MariaDB Enterprise Server for hardened production deployments, MariaDB ColumnStore for analytical workloads, and MariaDB Xpand, a distributed SQL engine for horizontal scaling. MariaDB Corporation also offers SkySQL, a fully managed cloud database-as-a-service with serverless, auto-scaling compute that can scale to zero during idle periods to reduce costs. Pricing follows a classic open-core model: the Community Server is entirely free to download, run, and modify, while MariaDB Enterprise Server and support subscriptions are priced commercially (typically ranging from roughly one thousand to well over ten thousand dollars per year depending on deployment scale), and SkySQL and Xpand are priced on a usage or resource-consumption basis. MariaDB's adoption is extensive: it ships as the default MySQL-compatible database in many major Linux distributions, including Red Hat Enterprise Linux, Fedora, and Debian, and is used by large-scale sites such as Wikipedia. Its primary competitors are MySQL itself (now owned by Oracle), PostgreSQL, Percona Server, and managed cloud database services like Amazon Aurora and Amazon RDS. MariaDB differentiates itself through vendor-neutral, foundation-governed open-source stewardship, MySQL compatibility without Oracle's licensing terms, additional storage engine and clustering options, and an enterprise support and cloud business that funds continued development without requiring users to give up control of the open-source core.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b06d1d19-b0b8-4c54-894b-14a56a483e6c';

