INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$CalDAV integration$q$, $q$Connects directly to any CalDAV-compatible server so tasks and events stay in an interoperable, self-controlled format.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Sub-tasks and recurrence$q$, $q$Tasks support due dates, status, descriptions, recurrence rules, and nested sub-tasks.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Multiple views$q$, $q$Switch between list, Gantt-style timeline, and calendar views, with customizable filters.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Multi-account support$q$, $q$Connect multiple CalDAV accounts and multiple user accounts from a single instance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$OAuth authentication$q$, $q$Supports OAuth-based login for securing access to the self-hosted instance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$SQLite support$q$, $q$Can run against SQLite for lightweight, low-maintenance deployments.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Docker deployment$q$, $q$Distributed as a multi-platform Docker image, and available through community Proxmox VE scripts.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Completely free and open source, with no subscription cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Keeps task and calendar data self-hosted and under user control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Works with existing CalDAV servers rather than locking data into a new format$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Actively developed, with visible GitHub releases into 2025$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Fits naturally into existing home-lab and Docker-based self-hosting setups$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Requires self-hosting knowledge and infrastructure to run$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Still in beta, so bugs and rough edges should be expected$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$No official managed/cloud-hosted version for non-technical users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Smaller community and support surface than mainstream productivity apps$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Feature set is narrower than established commercial to-do and calendar apps$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Is Manage My Damn Life free?$q$, $q$Yes, MMDL is free and open source; you only pay for whatever hosting you use to run it.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Do I need a CalDAV server to use it?$q$, $q$Yes, MMDL is a frontend for CalDAV data, so it needs to connect to a CalDAV server such as Nextcloud, Baikal, or Radicale.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Is there a hosted version I can just sign up for?$q$, $q$There is a public demo instance for evaluation, but MMDL is designed to be self-hosted rather than offered as a managed SaaS product.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$How is MMDL deployed?$q$, $q$It is distributed as a Docker image and is also available through community Proxmox VE installation scripts.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Is MMDL production-ready?$q$, $q$The maintainer describes it as beta software, so users should keep independent backups of their CalDAV data.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Who maintains Manage My Damn Life?$q$, $q$It is developed and maintained on GitHub under the intri-in account, as an independent open-source project.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Self-hosting enthusiasts$q$, $q$Individuals already running services like Nextcloud who want a dedicated, modern task and calendar UI on top of their existing CalDAV data.$q$, $q$Home-lab and self-hosting hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Privacy-focused task management$q$, $q$People who prefer to keep personal task and calendar data off commercial cloud platforms while still getting a usable app experience.$q$, $q$Privacy-conscious individuals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Shared household task tracking$q$, $q$Using multiple user and CalDAV accounts from one instance to coordinate tasks and calendars across a household.$q$, $q$Households and small shared deployments$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$Self-hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source software","Unlimited use on your own infrastructure","Multiple CalDAV and user accounts","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Manage My Damn Life (MMDL) is a self-hosted, open-source frontend for CalDAV tasks and calendars. Instead of locking your to-do list and calendar into a proprietary cloud service, MMDL connects to a CalDAV server you already run or control and presents that data through a clean, modern web interface.$q$, $q$The project is developed in the open on GitHub under intri-in/manage-my-damn-life-nextjs and is aimed at people who already self-host other services and want the same level of control over their task and calendar data. It is explicitly labeled as beta software, so it is best suited to users comfortable with some rough edges.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MMDL supports creating tasks with due dates, status, descriptions, recurrence, and nested sub-tasks, and lets users switch between list, Gantt, and calendar views with customizable filters. It also supports multiple CalDAV servers and multiple user accounts from one deployment, which makes it usable by a household or small shared instance rather than just a single person.$q$, $q$On the technical side, it offers OAuth-based login, SQLite compatibility for simple hosting, and distribution as a multi-platform Docker image, which fits naturally into home-lab stacks alongside tools like Nextcloud or Radicale that already expose CalDAV.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MMDL itself is free and open source; there is no license fee, subscription, or paid tier for the software. The only ongoing cost is whatever infrastructure you use to host it, typically a small VPS, home server, or existing Proxmox/Docker environment.$q$, $q$This makes MMDL's total cost of ownership largely a function of hosting choices rather than software licensing, which is the main value proposition compared to paid, subscription-based task and calendar apps.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5876a809-20b6-4a29-bd49-189eea244f05', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Incident and request management$q$, $q$Log, track, and resolve IT incidents and service requests with configurable workflows.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Problem and change management$q$, $q$ITIL-aligned processes for root-cause problem management and controlled change management.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$CMDB and asset management$q$, $q$Track hardware, software, and their relationships in a configuration management database.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Self-service portal$q$, $q$End users can submit and track their own tickets and requests without contacting IT directly.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$AI-assisted ticketing (Zia)$q$, $q$Native AI features for automated categorization, sentiment analysis, and suggested resolutions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$SLA management$q$, $q$Define and monitor service level agreements with escalation rules and reporting.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Enterprise service management$q$, $q$Extend the same ticketing platform to HR, facilities, and finance departments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Cloud or on-premise deployment$q$, $q$Choose between a hosted cloud edition or self-managed on-premise installation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Genuinely usable free edition for small IT teams (up to 5 technicians)$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Deep ITIL process support including CMDB and change management$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$AI features included across editions without extra licensing cost$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Flexible cloud or on-premise deployment options$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Backed by Zoho's broad integration ecosystem and enterprise scale$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Interface can feel dated and cluttered compared to newer competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Full ITIL configuration has a steep learning curve for smaller teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$On-premise edition requires more hands-on IT administration$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Per-technician tiered pricing structure can be confusing to navigate$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Advanced enterprise service management features are reserved for higher tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Is ManageEngine ServiceDesk Plus free?$q$, $q$There is a free Standard edition for up to 5 technicians with unlimited tickets and end users; larger teams need a paid plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$How much does ServiceDesk Plus cost?$q$, $q$Paid cloud plans start at roughly $13 per technician per month, scaling up through Professional, Asset, and Enterprise tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Is ServiceDesk Plus cloud-based or on-premise?$q$, $q$Both options are available; you can run it as a hosted cloud service or install it on-premise.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Who makes ServiceDesk Plus?$q$, $q$It is developed by ManageEngine, the enterprise IT management division of Zoho Corporation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Does it support ITIL processes?$q$, $q$Yes, it supports ITIL-aligned incident, problem, and change management along with a CMDB.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$What are the main alternatives to ServiceDesk Plus?$q$, $q$Common alternatives include Freshservice, Jira Service Management, Zendesk, and ServiceNow.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Small IT team help desk$q$, $q$Small IT departments using the free edition to manage tickets without licensing cost.$q$, $q$Small business IT teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Enterprise ITIL service management$q$, $q$Mid-market and large organizations running full ITIL processes including change and problem management.$q$, $q$Enterprise IT operations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Multi-department enterprise service management$q$, $q$Organizations extending the same ticketing platform to HR, facilities, and finance service desks.$q$, $q$Shared services and enterprise operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Standard (Free)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 5 technicians","Unlimited tickets and end users","Basic incident management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Standard$q$, $q$From around $13/technician/month$q$, $q$Monthly or annual$q$, NULL, $q$["Incident management","Self-service portal","Basic reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Professional$q$, $q$Custom$q$, $q$Monthly or annual$q$, NULL, $q$["Problem and change management","SLA management","CMDB"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$Enterprise$q$, $q$Custom$q$, $q$Monthly or annual$q$, NULL, $q$["Full ITIL suite","Enterprise service management","Advanced asset management"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ServiceDesk Plus is ManageEngine's IT service management platform, built to support ITIL-aligned incident, problem, and change management alongside asset tracking and a configuration management database. It is part of the broader ManageEngine suite from Zoho Corporation.$q$, $q$The product is available as both a cloud service and an on-premise installation, and it extends beyond IT into enterprise service management, allowing departments like HR and facilities to run their own request workflows on the same underlying platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include incident and request management, problem and change management workflows, a CMDB for IT asset relationships, SLA management, and a self-service portal for end users to log and track their own requests.$q$, $q$ManageEngine has layered in native AI features (branded Zia) for ticket triage, categorization, and suggested responses across editions, along with reporting and analytics dashboards for tracking service desk performance against SLAs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa99e850-6bd2-45a1-aa7b-4b9df4d24c1e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ServiceDesk Plus offers a genuinely free Standard edition for up to 5 technicians, with no cap on tickets or end users, which is notable for a help desk product in this category.$q$, $q$Paid plans are priced per technician per month across Standard, Professional, Asset, and Enterprise tiers, with entry cloud pricing starting around $13 per technician per month and rising with deeper ITIL, asset management, and ESM functionality; on-premise licensing is also available.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$AI candidate scoring$q$, $q$Automatically ranks and recommends candidates against job requirements to speed up screening.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Kanban recruitment pipeline$q$, $q$Visual, drag-and-drop pipeline for tracking candidates through each hiring stage.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$LinkedIn sourcing extension$q$, $q$Browser extension for pulling candidate profiles directly into Manatal while sourcing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Recruitment CRM$q$, $q$Tracks client companies, contacts, and job orders alongside candidate data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Careers page builder$q$, $q$Publish customizable job listing pages to attract applicants directly.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Job board integrations$q$, $q$Post jobs and pull applicants from major job boards and channels.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Reporting and analytics$q$, $q$Dashboards for tracking pipeline performance and recruiting metrics.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Team collaboration tools$q$, $q$Shared notes, tags, and permissions for coordinating recruiting teams.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Affordable pricing compared to enterprise ATS platforms like Bullhorn$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Fast setup and easy-to-learn interface for new users$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Strong LinkedIn-based candidate sourcing tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$AI candidate scoring included across plans rather than sold separately$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Scales reasonably from solo recruiters to small and mid-sized agencies$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Lacks the deep back-office and VMS integrations larger staffing agencies need$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Reporting is less robust than more mature platforms like Greenhouse$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Lower tiers cap the number of active jobs and stored candidates$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Mobile app experience is less developed than the web platform$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Less suited to complex contract staffing workflows$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$How much does Manatal cost?$q$, $q$Plans start at $15 per user per month on the Professional tier with annual billing, rising through Enterprise and Enterprise Plus tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Is there a free trial?$q$, $q$Manatal offers a trial period so teams can test the platform before subscribing; check the current offer on their pricing page.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Is Manatal good for staffing agencies?$q$, $q$It works well for boutique permanent-placement agencies but lacks the VMS and back-office depth larger contract staffing firms often need.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Does Manatal use AI?$q$, $q$Yes, it includes AI-based candidate scoring and recommendations across its plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$What integrations does Manatal support?$q$, $q$It integrates with major job boards, LinkedIn sourcing via a browser extension, and various third-party recruiting tools.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$What are the best Manatal alternatives?$q$, $q$Common alternatives include Bullhorn, Greenhouse, Zoho Recruit, Ceipal, and Crelate.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Boutique recruitment agencies$q$, $q$Small permanent-placement agencies needing an affordable ATS and CRM without enterprise overhead.$q$, $q$Agencies with roughly 15 or fewer recruiters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$In-house talent acquisition$q$, $q$Corporate HR teams managing their own hiring pipeline without a dedicated enterprise ATS budget.$q$, $q$In-house HR and recruiting teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Bullhorn alternative for cost-conscious agencies$q$, $q$Agencies switching from spreadsheets or seeking a lower-cost alternative to enterprise ATS platforms.$q$, $q$Cost-conscious staffing and recruiting businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Professional$q$, $q$$15/user/month (annual)$q$, $q$Monthly or annual$q$, NULL, $q$["Limited active jobs","Up to 10,000 candidates","Kanban pipeline","Basic AI scoring"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Enterprise$q$, $q$$35/user/month (annual)$q$, $q$Monthly or annual$q$, NULL, $q$["Higher job and candidate limits","Advanced automation","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Enterprise Plus$q$, $q$$55/user/month (annual)$q$, $q$Monthly or annual$q$, NULL, $q$["Highest usage limits","Advanced customization","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$Custom$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Tailored limits and features for large organizations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Manatal is a cloud-based applicant tracking system and recruitment CRM designed for recruiters, staffing agencies, and in-house talent acquisition teams. Founded in 2019 and based in Bangkok, Thailand, it has grown into a widely used ATS for smaller and mid-sized recruiting operations.$q$, $q$The platform combines candidate sourcing, pipeline management, and AI-assisted candidate scoring in a single browser-based tool, positioning itself as a lower-cost, easier-to-onboard alternative to enterprise recruiting suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Manatal offers a visual Kanban recruitment pipeline, a browser extension for sourcing candidates directly from LinkedIn and other sites, and a recruitment CRM for managing client companies and job orders alongside candidates.$q$, $q$Its AI features score and recommend candidates against job requirements to help recruiters prioritize applicants, and the platform includes a customizable careers page builder, team collaboration tools, and reporting dashboards.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4790e8a-5afa-40c4-9e80-1e6489a84434', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Manatal's Professional plan starts at $15 per user per month on annual billing, covering a limited number of active jobs and stored candidates, with monthly billing priced higher.$q$, $q$Enterprise and Enterprise Plus tiers raise usage limits and unlock more advanced automation and support, and a Custom plan is available for larger organizations with specific requirements.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$KWFinder keyword research$q$, $q$Find low-competition, long-tail keywords with search volume and difficulty data, including local city-level results.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$SERPChecker$q$, $q$Analyze search engine results pages to evaluate ranking difficulty and competitor strength.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$SERPWatcher rank tracking$q$, $q$Track keyword rankings over time with visual reporting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$LinkMiner backlink checker$q$, $q$Analyze backlink profiles for your site or competitors.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$SiteProfiler$q$, $q$Get a quick competitive overview of any domain's SEO metrics.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Unified dashboard$q$, $q$Access all five tools from one account rather than separate subscriptions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Browser extension$q$, $q$Check on-page SEO metrics directly while browsing.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Significantly more affordable than Ahrefs or Semrush$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Beginner-friendly interface that is easy to learn quickly$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$All five tools bundled into every paid plan$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Strong local and city-level keyword research capability$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$No long-term contract required; monthly billing available$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Smaller keyword and backlink database than Ahrefs or Semrush$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Not built for enterprise-scale technical SEO audits$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Fewer third-party integrations than larger SEO platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Usage limits (credits) can be restrictive on the Basic plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$No permanent free-forever plan for full tool access$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$What tools are included in Mangools?$q$, $q$Mangools includes KWFinder, SERPChecker, SERPWatcher, LinkMiner, and SiteProfiler, all bundled into every paid plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Is there a free trial?$q$, $q$Mangools offers a free trial period so users can test the suite before subscribing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$How much does Mangools cost?$q$, $q$Paid plans start at around $29.90 per month for Basic when billed annually, up to around $89.90 per month for Agency.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$How does Mangools compare to Ahrefs or Semrush?$q$, $q$Mangools is more affordable and simpler to use, but has a smaller keyword and backlink database than those larger platforms.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Is Mangools good for beginners?$q$, $q$Yes, it is frequently recommended as an approachable first SEO tool due to its simple interface and lower price.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Where is Mangools based?$q$, $q$Mangools is headquartered in Bratislava, Slovakia, and is a self-funded, bootstrapped company.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Freelance SEO and content work$q$, $q$Independent SEOs and bloggers doing keyword research and rank tracking on a budget.$q$, $q$Freelancers and solo content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Small business self-managed SEO$q$, $q$Business owners handling their own SEO without hiring an agency or buying enterprise tools.$q$, $q$Small business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Small agency client reporting$q$, $q$Small agencies needing affordable, easy-to-understand SEO tools and reports for multiple clients.$q$, $q$Small SEO and marketing agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Basic$q$, $q$$29.90/month (annual billing)$q$, $q$Monthly or annual$q$, NULL, $q$["All five Mangools tools","Standard usage credits","Single user"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Premium$q$, $q$$44.90/month (annual billing)$q$, $q$Monthly or annual$q$, NULL, $q$["Higher usage credits","More tracked keywords","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$Agency$q$, $q$$89.90/month (annual billing)$q$, $q$Monthly or annual$q$, NULL, $q$["Highest usage credits","Multiple team members","Client-ready reporting"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mangools is a Bratislava-based SEO software suite that started as the keyword research tool KWFinder in 2014 and expanded into a five-tool platform under the Mangools brand in 2016. It is self-funded and has grown without external venture capital.$q$, $q$The suite bundles keyword research, SERP analysis, rank tracking, backlink checking, and site auditing into a single subscription, targeting beginner and intermediate SEO users rather than enterprise teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core toolset includes KWFinder for keyword research (with strong support for local, city-level keyword data), SERPChecker for analyzing search results, and SERPWatcher for rank tracking over time.$q$, $q$It also includes LinkMiner for backlink analysis and SiteProfiler for a quick competitive site overview, all accessible from one dashboard along with a browser extension for on-page SEO checks.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1677b9b7-dd62-421f-95ae-ac5647c1cc29', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mangools offers three paid tiers: Basic at around $29.90 per month, Premium at around $44.90 per month, and Agency at around $89.90 per month, all on annual billing, with monthly billing priced higher.$q$, $q$Every plan includes access to all five tools, with higher tiers unlocking larger usage limits (more keyword lookups, tracked keywords, and backlink queries) rather than gating specific tools behind higher-priced plans.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$SQL-native querying$q$, $q$Query via SQL over the MySQL protocol or HTTP, usable with standard MySQL client libraries.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Full-text search engine$q$, $q$Over 20 full-text operators and ranking factors with custom rankers and tokenization.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Real-time and offline indexes$q$, $q$Supports both real-time indexing and traditional offline (plain) index building.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Vector and hybrid search$q$, $q$Combines full-text and vector search for modern semantic and hybrid retrieval use cases.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Distributed indexing$q$, $q$Built-in load balancer and distributed index support for scaling across nodes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Elasticsearch-compatible ingestion$q$, $q$JSON HTTP API compatible with Elasticsearch-style insert and replace operations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Multi-language clients$q$, $q$Official client libraries for PHP, Python, JavaScript, TypeScript, Java, Go, and Rust.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Data source connectors$q$, $q$Sync data from MySQL, PostgreSQL, ODBC, XML, and CSV sources.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Free and open source with an active development community$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Faster and more resource-efficient than Elasticsearch in published benchmarks$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Familiar SQL interface lowers the learning curve for relational database users$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Supports hybrid full-text and vector search in one engine$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Lightweight footprint suitable for smaller infrastructure budgets$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Smaller community and ecosystem than Elasticsearch or OpenSearch$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Managed cloud offering has less regional coverage than major cloud search services$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Documentation has gaps for some advanced configuration scenarios$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Enterprise support organization is smaller than larger competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Requires search-domain knowledge to tune ranking and relevance effectively$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Is Manticore Search free?$q$, $q$Yes, the core engine is open source and free to self-host; paid options exist for managed cloud hosting and enterprise support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Is Manticore Search a fork of Sphinx?$q$, $q$Yes, it was forked from Sphinx in 2017 by former core Sphinx team members after Sphinx's development stalled.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$How is Manticore different from Elasticsearch?$q$, $q$Manticore uses a SQL-native interface and is marketed as faster and more resource-efficient, while Elasticsearch has a larger ecosystem and community.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Does Manticore Search support vector search?$q$, $q$Yes, it supports vector search and hybrid full-text-plus-vector search.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$What languages have client libraries?$q$, $q$PHP, Python, JavaScript, TypeScript, Java, Go, Rust, and Elixir all have official or community client libraries.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Can I use MySQL clients with Manticore?$q$, $q$Yes, Manticore supports SQL over the MySQL wire protocol, so standard MySQL clients can connect to it.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Self-hosted application search$q$, $q$Developers adding full-text search to web or e-commerce applications without running a full Elasticsearch cluster.$q$, $q$Backend and platform engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Migrating off Sphinx$q$, $q$Teams still on the original Sphinx search engine looking for an actively maintained, compatible successor.$q$, $q$Legacy Sphinx users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Log and data analytics search$q$, $q$Teams needing fast full-text search over large log or analytics datasets with lower resource overhead.$q$, $q$Data and infrastructure teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source engine","Self-hosted deployment","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Manticore Search Cloud$q$, $q$Usage-based$q$, $q$Monthly$q$, NULL, $q$["Managed hosting","Automatic scaling","Operational monitoring"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$Enterprise Support$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Dedicated support","Professional services","SLA-backed assistance"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Manticore Search is an open-source search database forked from Sphinx in 2017 by former core Sphinx contributors, after the original project's development stalled. It is maintained by Manticore Software Ltd, based in Gillingham, Kent, UK.$q$, $q$It is designed as a fast, SQL-native alternative to Elasticsearch and OpenSearch, supporting full-text, vector, and hybrid search with real-time indexing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Manticore supports SQL over both MySQL protocol and HTTP, a JSON API compatible with Elasticsearch-style writes, more than 20 full-text operators and ranking factors, and both real-time and offline indexes.$q$, $q$It also offers distributed indexing with built-in load balancing, geo search, vector and hybrid search, and connectors for MySQL, PostgreSQL, ODBC, XML, and CSV data sources.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Manticore Search engine is free and open source, with no license fee for self-hosted use.$q$, $q$Manticore Software generates revenue through Manticore Search Cloud, a managed hosting option, along with paid professional services and enterprise support subscriptions, rather than by charging for the core software.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8eeed669-fbb5-47e4-8555-27145e4a692e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Automatic model indexing$q$, $q$Point Manyfold at a folder of STL/3MF/OBJ files and it automatically indexes and catalogs them.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$3D previews and thumbnails$q$, $q$Generates browsable 3D previews and thumbnails for every indexed model.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Metadata extraction$q$, $q$Extracts dimensions, polygon counts, and other metadata directly from model files.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Tagging and search$q$, $q$Organize and find models quickly with tags and full-text search.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Public and private sharing$q$, $q$Share individual models or collections publicly or keep them private.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Fediverse federation$q$, $q$Follow content on other Manyfold instances or across the wider Fediverse.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Docker deployment$q$, $q$Distributed as a multi-platform Docker image for easy self-hosting.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Home-lab platform support$q$, $q$Available via community install scripts for Unraid, Cloudron, and Proxmox VE.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Completely free and open source with no paid tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Automatic indexing and metadata extraction saves manual organizing time$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Data stays fully self-hosted and under user control$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Active community development on GitHub$q$, 3);
