INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Requires self-hosting and some technical setup knowledge$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$No official managed or cloud-hosted version$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Smaller community and support surface than commercial tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Feature set is narrower than some paid 3D asset management platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Mobile browsing experience is more limited than a native app$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Is Manyfold free?$q$, $q$Yes, Manyfold is fully free and open source under the AGPL-3.0 license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$What file formats does Manyfold support?$q$, $q$It primarily supports STL files, along with 3MF and OBJ model formats.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$How do I install Manyfold?$q$, $q$Manyfold is distributed as a Docker image and is also available via community install scripts for platforms like Proxmox VE and Cloudron.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Is there a hosted version of Manyfold?$q$, $q$There is a public demo instance at try.manyfold.app, but Manyfold is designed to be self-hosted rather than offered as a managed SaaS.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Can I share my 3D model library with others?$q$, $q$Yes, Manyfold supports public and private sharing, plus federation with other instances over the Fediverse.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Who maintains Manyfold?$q$, $q$It is maintained as an open-source community project on GitHub under the manyfold3d organization.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Hobbyist 3D printer library management$q$, $q$Organizing large personal collections of downloaded and designed STL files.$q$, $q$3D printing hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Maker community and print farm organization$q$, $q$Managing shared model libraries across a maker space or small print farm.$q$, $q$Maker communities and print farms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Self-hosting a Plex-like experience for 3D files$q$, $q$Self-hosting enthusiasts wanting a browsable, searchable interface for their 3D model files alongside other home-lab services.$q$, $q$Home-lab and self-hosting enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$Self-hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source feature set","Unlimited models on your own infrastructure","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Manyfold is an open-source, self-hosted digital asset manager purpose-built for 3D printing model files. It automatically indexes STL, 3MF, and OBJ files, generating thumbnails, previews, and searchable metadata for large model libraries.$q$, $q$The project is maintained as a community effort on GitHub, built with Ruby on Rails and released under the AGPL-3.0 license, with no company or paid tier behind it.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Manyfold automatically scans a folder of 3D print files, extracting metadata like dimensions and polygon counts, and presents them with thumbnails, tags, and full 3D previews in a searchable web interface.$q$, $q$It supports public or private sharing of content and can federate with other Manyfold instances or the wider Fediverse, letting users follow and discover models across separate self-hosted instances.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Manyfold is completely free and open source, with no license fee, subscription, or paid tier. It is distributed as a multi-platform Docker image for self-hosting.$q$, $q$There is no official managed cloud version; the only cost is whatever hosting infrastructure a user runs, such as a home server, NAS, or small VPS, and a public demo instance is available for evaluation.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ded501a2-3874-4feb-b810-f1dff8c8fb1d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$Automated invoice processing$q$, $q$OCR-based extraction turns vendor invoices into structured line-item data without manual entry.$q$, 0);
