INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$MarginEdge + Freepour$q$, $q$Add-on module for beverage and liquor cost tracking.$q$, 6);
