INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$How much does MarginEdge cost?$q$, $q$The core platform costs $350 per month per location, with an annual prepay option saving roughly 10%.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$What does MarginEdge replace?$q$, $q$It replaces manual invoice entry, spreadsheet-based food costing, and disconnected accounting workflows.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$Does MarginEdge integrate with accounting software?$q$, $q$Yes, it integrates with systems such as QuickBooks to sync invoice and cost data automatically.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$Who is MarginEdge for?$q$, $q$It is built for independent restaurants and multi-unit restaurant groups that want automated invoice processing and real-time food cost visibility.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$What is MarginEdge + Freepour?$q$, $q$It is an add-on module priced at $500 per month per location that adds beverage and liquor cost tracking.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$What are MarginEdge's main competitors?$q$, $q$Key competitors include Restaurant365, Compeat, Craftable, and Toast's xtraCHEF.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$Independent restaurant back-office automation$q$, $q$Single-location restaurants automating manual invoice entry and food cost tracking.$q$, $q$Independent restaurant owners and managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$Multi-unit restaurant group reporting$q$, $q$Restaurant groups needing centralized, real-time cost reporting across many locations.$q$, $q$Multi-unit restaurant operators and hospitality groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$Restaurant accounting and bookkeeping$q$, $q$Accountants and bookkeepers needing clean integration between vendor invoices and the general ledger.$q$, $q$Restaurant accountants and bookkeepers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$Core$q$, $q$$350/month per location$q$, $q$Monthly or annual (annual saves ~10%)$q$, NULL, $q$["Automated invoice processing","Food cost and recipe tracking","Inventory management","Accounting integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$MarginEdge + Freepour$q$, $q$$500/month per location$q$, $q$Monthly or annual (annual saves ~10%)$q$, NULL, $q$["All Core features","Beverage and liquor cost tracking"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MarginEdge is a restaurant back-office platform that automates invoice processing, food cost tracking, and accounting integration for restaurant operators. It was founded in 2015 by former restaurant operators and is headquartered in Arlington, Virginia.$q$, $q$The company has raised roughly $83.2 million in venture funding across multiple rounds, including an $18 million round in 2021 and a $45 million Series C led by Ten Coves Capital, and was named a 2025 Inc. 5000 honoree.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MarginEdge digitizes vendor invoices using OCR-based data extraction, eliminating manual line-item entry, and feeds that data into real-time food cost tracking, recipe costing, and inventory management.$q$, $q$It integrates with accounting systems like QuickBooks, offers AI-driven demand forecasting, and provides a Freepour add-on for beverage and liquor cost tracking.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('adae3e2d-9b36-4cc0-8d29-a710afd0f677', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core MarginEdge platform costs $350 per month per restaurant location, with the MarginEdge + Freepour beverage tracking add-on priced at $500 per month per location.$q$, $q$Customers can choose monthly billing or an annual prepay option that saves roughly 10% compared to paying month to month.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$MySQL compatibility$q$, $q$Drop-in replacement for MySQL, supporting most existing applications, drivers, and SQL syntax.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Pluggable storage engines$q$, $q$Choose different storage engines optimized for different workloads within the same database.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$MariaDB Enterprise Server$q$, $q$Hardened, commercially supported release for production enterprise deployments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$MariaDB ColumnStore$q$, $q$Columnar storage engine built for analytical and reporting workloads.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$MariaDB Xpand$q$, $q$Distributed SQL engine for horizontal scaling across nodes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$SkySQL managed cloud$q$, $q$Fully managed, serverless cloud database-as-a-service with auto-scaling.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$GPL open-source licensing$q$, $q$Free to use, modify, and redistribute under the GNU General Public License.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Foundation governance$q$, $q$Nonprofit MariaDB Foundation oversees the open-source project independently of commercial interests.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Completely free and open source for self-hosted use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Drop-in compatibility makes migration from MySQL straightforward for most workloads$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Widely adopted as the default database in major Linux distributions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Additional storage engines and clustering options beyond stock MySQL$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Enterprise support available without full vendor lock-in, thanks to foundation governance$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Enterprise support and SkySQL pricing can be significant at larger scale$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Some newer MySQL features have diverged or lag between the two projects$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$SkySQL's cloud footprint is smaller than AWS, GCP, or Azure managed database offerings$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Requires DBA expertise to fully exploit storage engine and clustering options$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Migration from MySQL still requires compatibility testing for edge cases$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Is MariaDB free?$q$, $q$Yes, the Community Server is free and open source; paid options exist for enterprise support, hardened releases, and cloud hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Is MariaDB compatible with MySQL?$q$, $q$Yes, it is designed as a drop-in replacement, supporting most MySQL applications, drivers, and SQL syntax.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Who governs MariaDB development?$q$, $q$The nonprofit MariaDB Foundation oversees the open-source project, while MariaDB plc develops commercial products and services around it.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$What is SkySQL?$q$, $q$SkySQL is MariaDB's fully managed, serverless cloud database-as-a-service with automatic scaling.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$What is the difference between the MariaDB Foundation and MariaDB Corporation?$q$, $q$The Foundation is a nonprofit that governs the open-source codebase, while MariaDB Corporation (now MariaDB plc) is the commercial entity selling enterprise products and support.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$What are MariaDB's main competitors?$q$, $q$Its main competitors are MySQL, PostgreSQL, Percona Server, and managed cloud databases like Amazon Aurora and RDS.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Free MySQL-compatible database for startups$q$, $q$Startups and open-source projects wanting a free, MySQL-compatible database without licensing cost.$q$, $q$Startups and open-source developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Vendor-neutral enterprise database$q$, $q$Enterprises wanting an open-source database with paid support but without single-vendor lock-in.$q$, $q$Enterprise IT and database teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Distributed and cloud-scale SQL$q$, $q$Teams needing horizontally scalable SQL via Xpand or managed cloud hosting via SkySQL.$q$, $q$Platform and infrastructure engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$Community Server$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source database engine","Self-hosted deployment","Community support"]$q$::jsonb, 0);
