INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MariaDB is an open-source relational database forked from MySQL in 2009 by MySQL's original creators, including Michael 'Monty' Widenius, following Oracle's acquisition of Sun Microsystems. It was designed to remain free and community-governed under the GNU General Public License.$q$, $q$The project is governed by a nonprofit MariaDB Foundation formed in 2012, alongside a commercial entity, now MariaDB plc, that sells enterprise products, support, and cloud services built on the open-source core.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MariaDB is a drop-in replacement for MySQL, supporting most of the same SQL syntax, drivers, and applications, while adding a pluggable storage engine architecture that lets users pick engines suited to different workloads.$q$, $q$The broader product family includes MariaDB Enterprise Server for production hardening, MariaDB ColumnStore for analytics, MariaDB Xpand for distributed SQL at scale, and SkySQL, a managed cloud database-as-a-service with serverless auto-scaling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b06d1d19-b0b8-4c54-894b-14a56a483e6c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The MariaDB Community Server is completely free to download, run, and modify under its open-source license, with no cost for self-hosted use.$q$, $q$MariaDB Enterprise Server and support subscriptions are priced commercially for organizations needing hardened releases and vendor support, while SkySQL and Xpand are priced based on compute and resource usage in the cloud.$q$]::text[], 2);
